solution_code:
#include <iostream>

auto double_value(int x)
{
    return x * 2;
}

auto quadruple_value(int x)
{
    return double_value(x) * 2;
}

int main()
{
    int n;
    std::cin >> n;
    std::cout << "Double: " << double_value(n) << '\n';
    std::cout << "Quad: "   << quadruple_value(n) << '\n';
    return 0;
}

