#include <iostream>
#include <iomanip>

auto average(int a, int b)
{
    return (a + b) / 2;  // BUG: integer division discards fractional part
}

int main()
{
    int a, b;
    std::cin >> a >> b;
    std::cout << "Average: "
              << std::fixed << std::setprecision(1)
              << average(a, b) << '\n';
    return 0;
}

solution_code:
#include <iostream>
#include <iomanip>

auto average(int a, int b)
{
    return (a + b) / 2.0;
}

int main()
{
    int a, b;
    std::cin >> a >> b;
    std::cout << "Average: "
              << std::fixed << std::setprecision(1)
              << average(a, b) << '\n';
    return 0;
}
